    def create_topics_batch(
        self, topics: List[Dict[str, Any]]
    ) -> Dict[str, bool]:
        """
        Create multiple topics in a batch.

        Args:
            topics: List of dicts with keys: name, partitions, replication_factor, configs
        """
        if not self.admin_client:
            logger.error("Not connected to Kafka cluster.")
            return {}

        results = {}
        new_topics = []

        for topic_spec in topics:
            name = topic_spec["name"]
            new_topic = NewTopic(
                name=name,
                num_partitions=topic_spec.get("partitions", 1),
                replication_factor=topic_spec.get("replication_factor", 1),
                topic_configs=topic_spec.get("configs", {}),
            )
            new_topics.append(new_topic)

        try:
            logger.info(f"Creating {len(new_topics)} topics in batch...")
            self.admin_client.create_topics(
                new_topics=new_topics,
                validate_only=False,
            )
            for topic_spec in topics:
                results[topic_spec["name"]] = True
                logger.info(f"  Topic '{topic_spec['name']}' created successfully.")

        except TopicAlreadyExistsError as e:
            logger.warning(f"One or more topics already exist: {e}")
            # Try creating individually to identify which ones failed
            for topic_spec in topics:
                if topic_spec["name"] not in results:
                    results[topic_spec["name"]] = self.create_topic(
                        topic_name=topic_spec["name"],
                        num_partitions=topic_spec.get("partitions", 1),
                        replication_factor=topic_spec.get("replication_factor", 1),
                        topic_configs=topic_spec.get("configs", {}),
                    )
        except KafkaError as e:
            logger.error(f"Batch topic creation failed: {e}")
            for topic_spec in topics:
                results.setdefault(topic_spec["name"], False)

        return results

