def parse_config_args(config_list: Optional[List[str]]) -> Dict[str, str]:
    """Parse config arguments in the format key=value."""
    configs = {}
    if config_list:
        for config_str in config_list:
            if "=" not in config_str:
                logger.warning(
                    f"Invalid config format '{config_str}', expected key=value. Skipping."
                )
                continue
            key, value = config_str.split("=", 1)
            configs[key.strip()] = value.strip()
    return configs


